// Java 26 - Final field restrictions (JEP 500)
// Learn: deep reflection over final fields now needs explicit migration opt-in.
class Invoice {
    final int amount;
    Invoice(int amount) { this.amount = amount; }
}

Invoice invoice = new Invoice(42);
var field = Invoice.class.getDeclaredField("amount"); // getDeclaredField("amount") finds the final field.
field.setAccessible(true);
field.set(invoice, 99); // Java 26 warns unless final-field mutation is enabled.
System.out.println(invoice.amount);
